import React, { Component } from 'react';
import '../collapse.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import listPlugin from '@fullcalendar/list'
import Moment from 'moment'
import Collapsible from "react-collapsible"
import { properties } from '../../properties/properties.js'
import $ from 'jquery'


class Calendar extends Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], teamValue: "", screen: 0, dateStr: "", teamId: "", incompleteEval: [], createEvalResult: [], disableSubmitButton: true, statusEval: [], setCalendarDate: ""
        };

    }


        componentDidMount() {



            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `getAmionOff`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                this.setState({screen: 1})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }


          handleEvents = (dateInfo) => {

            var renderedEvents = $('.fc-list-table  tr');
            var reorderedEvents = [];
            var blockEvents = null;
            renderedEvents.map(function(key, event) {
              if ($(event).hasClass('fc-list-day')) {
                if (blockEvents) {
                  reorderedEvents.unshift(blockEvents.children());
                }
                blockEvents = $('<tbody></tbody>');
              }
              blockEvents.append(event);
            });
            if (blockEvents){
              reorderedEvents.unshift(blockEvents.children());
              $('.fc-list-table tbody').html(reorderedEvents);
            }

          }


          handleDidMount = (info) => {

            //console.log(info)

              var allDayList = document.getElementsByClassName("fc-list-event-time")
              //console.log(allDayList)
              for (var i = 0; i < allDayList.length; i++) {
                allDayList[i].style.display = "none"; 
              }

              var dotEl = info.el.getElementsByClassName('fc-list-event-dot')[0];
              if (dotEl) {
                //dotEl.style.backgroundColor = 'white';
                dotEl.style.display  = "none"; 
              }

              if (info.event.extendedProps.team.includes("SFCards")) {
                info.el.style.backgroundColor = '#F5F5F5';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }

              if (info.event.extendedProps.team.includes("SFW")) {
                info.el.style.backgroundColor = '#ffffe6';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }

              if (info.event.extendedProps.team.includes("UCW")) {
                info.el.style.backgroundColor = '#e6ffff';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }

              if (info.event.extendedProps.team.includes("VAW")) {
                info.el.style.backgroundColor = '#ffe6e6';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }


              if (info.event.extendedProps.team.includes("UC Cards")) {
                info.el.style.backgroundColor = '#d9e6f2';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }

              if (info.event.extendedProps.team.includes("UC Gen")) {
                info.el.style.backgroundColor = '#d9e6f2';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }

              if (info.event.extendedProps.team.includes("CCU")) {
                info.el.style.backgroundColor = '#d9e6c1';
                info.el.style.color = "black";
                info.el.style.borderColor = "#CCCCCC"
              }

              if (info.event.extendedProps.status === 'team') {
                // Change background color of row
                info.el.style.backgroundColor = '#76b5c5';
                info.el.style.color = "black";

                // Change color of dot marker
                var dotEl = info.el.getElementsByClassName('fc-list-event-dot')[0];
                if (dotEl) {
                  //dotEl.style.backgroundColor = 'white';
                  dotEl.style.display  = "none"; 
                }
              }


              if (info.event.extendedProps.status === 'faculty') {
                // Change background color of row
                info.el.style.backgroundColor = '#D9f3f9';
                if (info.event.extendedProps.evalError.length > 0) {
                  info.el.style.color = 'red'
                }

                // Change color of dot marker
                var dotEl = info.el.getElementsByClassName('fc-list-event-dot')[0];
                if (dotEl) {
                    if (info.event.extendedProps.evalStatus === 'Incomplete') {
                        dotEl.style.borderColor = '#e28743';
                    } else {
                        dotEl.style.borderColor = '#1e81b0';
                    }
                    if (info.event.extendedProps.evalError.length > 0) {
                      dotEl.style.borderColor = 'red'
                    }
                  //dotEl.style.display  = "none"; 
                }
              }

              if (info.event.extendedProps.status === 'resident') {
                // Change background color of row
                info.el.style.backgroundColor = '#F9edd9';
                if (info.event.extendedProps.evalError.length > 0) {
                  info.el.style.color = 'red'
                }
                // Change color of dot marker
                var dotEl = info.el.getElementsByClassName('fc-list-event-dot')[0];
                if (dotEl) {
                    if (info.event.extendedProps.evalStatus === 'Incomplete') {
                        dotEl.style.borderColor = '#e28743';
                    } else {
                        dotEl.style.borderColor = '#1e81b0';
                    }
                    if (info.event.extendedProps.evalError.length > 0) {
                      dotEl.style.borderColor = 'red'
                    }
                  //dotEl.style.display  = "none"; 
                }
              }


              if (info.event.extendedProps.status === 'intern') {
                // Change background color of row
                info.el.style.backgroundColor = '#F9f7d9';
                if (info.event.extendedProps.evalError.length > 0) {
                  info.el.style.color = 'red'
                }
                // Change color of dot marker
                var dotEl = info.el.getElementsByClassName('fc-list-event-dot')[0];
                if (dotEl) {
                    if (info.event.extendedProps.evalStatus === 'Incomplete') {
                        dotEl.style.borderColor = '#e28743';
                    } else {
                        dotEl.style.borderColor = '#1e81b0';
                    }
                    if (info.event.extendedProps.evalError.length > 0) {
                      dotEl.style.borderColor = 'red'
                    }
                  //dotEl.style.display  = "none"; 
                }
              }



          }


    render() {


        var content = []
        var events = []

        /*
        content.push(                 <FullCalendar
            plugins={[ dayGridPlugin, interactionPlugin, listPlugin ]}
            initialView="listMonth"
            events={events}
            //eventClick={this.handleEventClick}
            //dateClick={this.handleDateClick}
            eventOrder="id"
            eventDidMount={this.handleDidMount}
            initialDate= {this.state.setCalendarDate}
            eventsSet={this.handleEvents}
            //navLinkDayClick={this.handleLinkClick}

          />)
*/


if (this.state.screen === 1) {


    for (let x in this.state.results) {
        events.push({extendedProps: {team: this.state.results[x].team}, id: "", groupId: "",title: this.state.results[x].name + " - " + this.state.results[x].team,  date: Moment(this.state.results[x].date).format("YYYY-MM-DD"), color: "#FF7F7F", textColor: "black" })
    }



    content.push(                 <FullCalendar
      plugins={[ dayGridPlugin, interactionPlugin, listPlugin ]}
      initialView="dayGridMonth"
      //eventClick={this.handleEventClick}
      //dateClick={this.handleDateClick}
      eventOrder="id"
      initialDate={Moment().format("YYYY-MM-DD")}
      events={events}
      eventDidMount={this.handleDidMount}

    />)

} else {
    content.push(<div>Loading ...</div>)
}



        return (
            <div style={{minHeight: "500px", marginLeft: "50px"}}>{content}</div>
        );


    }
}

export default Calendar
